```python
class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = 'w'

    def switch_turn(self):
        if self.current_player == 'w':
            self.current_player = 'b'
        else:
            self.current_player = 'w'

    def is_valid_move(self, start, end):
        piece = self.board.board[start[0]][start[1]]
        if not piece or piece.color != self.current_player:
            return False

        # Check the move
        x_diff = abs(start[0] - end[0])
        y_diff = abs(start[1] - end[1])

        if x_diff == 1 and y_diff in (1, 2):
            if y_diff == 1:
                if self.board.board[end[0]][end[1]]:
                    return False
                else:
                    return True
            elif y_diff == 2:
                jump_piece = self.board.board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2]
                if jump_piece and jump_piece.color != piece.color and not jump_piece.king:
                    return True
        return False

    def make_move(self, start, end):
        if self.is_valid_move(start, end):
            piece = self.board.board[start[0]][start[1]]
            self.board.board[start[0]][start[1]] = None
            self.board.board[end[0]][end[1]] = piece
            self.switch_turn()
            return True
        else:
            print("Invalid move. Please try again.")
            return False

    def play(self):
        while True:
            self.board.print_board()
            start_pos = input(f"Player {self.current_player}, enter your move (from-to): ").split('-')
